<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>
        <div class="padding-t_10 p-0" id="reportstabsdata">
            <div class="left-menu-tab mt-2">
                <div class="col-md-12 p-0">
                    <div class="theme-primary partition">
                        <span class="p-name text-white">{{ $t("Billing") }}</span>
                    </div>
                </div>
                <ul class="nav nav-pills flex-column left-tab mt-2 responivecustomtab nav-tabs">
                    <li
                        v-for="tab in tabsWithLocalization"
                        :key="tab.id"
                        @click="changeTab(tab)"
                        :class="{
                            'nav-item': true,
                            'active': currentTab && currentTab.id === tab.id
                        }"
                    >
                        <span :class="{
                            'nav-link left-menu': true,
                            'active': currentTab && currentTab.id === tab.id
                        }">
                            <i :class="tab.icon" class="p-1"></i> {{ tab.displayName }}
                        </span>
                    </li>
                </ul>
            </div>
            <div class="right-content">
                <div class="tab-content" id="myTabContent">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
                            <i class="icon-solid arrow-solid-left text-white" style="font-size:9pt"></i>
                        </a>
                    </div>
                    <!-- <div class="theme-primary partition p-actions-expand mt-2" v-if="currentTab">
                        <span class="p-name text-white">{{ currentTab.displayName }}</span>
                        <RouterLink to="/BillingValidationData" title="" class="p-action-btn text-white float-right"
                            data-toggle-tooltip="tooltip" data-original-title="Back to list">
                            <i class="fa fa-angle-double-left pr-2"></i><br>{{ $t("BacktoList") }}
                        </RouterLink>
                    </div> -->
                    <div class="col-md-12 p-0" v-if="currentTab && !isUnauthorized">
                        <!-- Tab Content Components -->
                        <keep-alive>
                            <component :is="currentComponent"></component>
                        </keep-alive>
                    </div>
                    <div class="col-md-12 p-0" v-else-if="isUnauthorized">
                        <Unauthorized />
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import Loader from "../../components/Common/Loader.vue";
import FlagRecords from "./components/FlagRecords.vue";
import BilledUnbilledRecords from "./components/BilledUnbilledRecords.vue";
import BulkMove from "./components/BulkMove.vue";
import BulkMoveAdvance from "./components/BulkMoveAdvance.vue";
import TicketLog from "./components/TicketLog.vue";
import UnprocessedRecords from "./components/UnprocessedRecords.vue";
import PreviewInvoice from "./components/PreviewInvoice.vue";
import Unauthorized from '../auth/Unauthorized.vue';
import DataService from '../../services/DataService.js';

export default {
    components: {
        Loader,
        FlagRecords,
        BilledUnbilledRecords,
        BulkMove,
        BulkMoveAdvance,
        TicketLog,
        UnprocessedRecords,
        PreviewInvoice,
        Unauthorized
    },
    data() {
        return {
            isLoading: false,
            isUnauthorized: false,
            tabs: [
                { 
                    id: 1, 
                    title: "FlagRecords", 
                    displayName: "FlagRecords", 
                    icon: "fa fa-flag", 
                    route: "flag-records" 
                },
                { 
                    id: 2, 
                    title: "BilledUnbilledRecords", 
                    displayName: "BilledUnbilledRecords", 
                    icon: "fa fa-usd", 
                    route: "billed-unbilled-records" 
                },
                { 
                    id: 3, 
                    title: "BulkMove", 
                    displayName: "BulkMove", 
                    icon: "fa fa-arrows", 
                    route: "bulk-move" 
                },
                { 
                    id: 4, 
                    title: "BulkMoveAdvance", 
                    displayName: "BulkMoveAdvance", 
                    icon: "fa fa-arrows-alt", 
                    route: "bulk-move-advance" 
                },
                { 
                    id: 5, 
                    title: "TicketLog", 
                    displayName: "TicketLog", 
                    icon: "fa fa-ticket", 
                    route: "ticket-log" 
                },
                { 
                    id: 6, 
                    title: "UnprocessedRecords", 
                    displayName: "UnprocessedRecords", 
                    icon: "fa fa-th-list", 
                    route: "unprocessed-records" 
                },
                { 
                    id: 7, 
                    title: "PreviewInvoice", 
                    displayName: "PreviewInvoice", 
                    icon: "fa fa-eye", 
                    route: "preview-invoice" 
                }
            ],
            currentTab: null
        }
    },
    computed: {
        tabsWithLocalization() {
            return this.tabs.map(tab => ({
                ...tab,
                displayName: this.$t(tab.title)
            }));
        },
        currentComponent() {
            if (!this.currentTab) return null;
            switch (this.currentTab.id) {
                case 1: return 'FlagRecords';
                case 2: return 'BilledUnbilledRecords';
                case 3: return 'BulkMove';
                case 4: return 'BulkMoveAdvance';
                case 5: return 'TicketLog';
                case 6: return 'UnprocessedRecords';
                case 7: return 'PreviewInvoice';
                default: return null;
            }
        }
    },
    created() {
        this.initializeTab();
    },
    watch: {
        '$route'(to, from) {
            this.initializeTab();
        }
    },
    methods: {
        initializeTab() {
            const tabRoute = this.$route.params.tab || 'flag-records';
            const tab = this.tabs.find(t => t.route === tabRoute);

            if (tab) {
                this.checkPrivilegeAndSetTab(tab);
            } else {
                // Default to first tab if route doesn't match
                const defaultTab = this.tabs[0];
                this.checkPrivilegeAndSetTab(defaultTab);
                // Update URL to match default tab if needed
                if (this.$route.params.tab !== defaultTab.route) {
                    this.$router.replace({
                        name: 'BillingValidationData',
                        params: { tab: defaultTab.route }
                    });
                }
            }
        },
        checkPrivilegeAndSetTab(tab, updateRoute = false) {
            this.isLoading = true;
            const privilegeMap = {
                'flag-records': 'controller=BillingValidationData&action=flag-records',
                'billed-unbilled-records': 'controller=BilledUnbilledRecords&action=ProUnproRecords',
                'bulk-move': 'controller=BulkMoveUsingFile&action=BulkMoveOperationList',
                'bulk-move-advance': 'controller=BulkMoveUsingFile&action=BulkMoveOperationList',
                'ticket-log': 'controller=TicketLog&action=TicketLog',
                'unprocessed-records': 'controller=UnprocessedRecords&action=UnprocessedRecord',
                'preview-invoice': 'controller=PreviewInvoice&action=View'
            };

            // fallback default (optional but safe)
            const privilegeParams =
                privilegeMap[tab.route] ||
                'controller=FlagRecords&action=CatchAll';

            DataService.CheckPrivilege(privilegeParams).then(response => {
                if (tab.route === 'preview-invoice') {
                    if (response.data) {
                         window.location.href = `/InvoiceReport/Index?tab=Preview%20Invoice`;
                         ////vm.$router.push('/InvoiceReport/Index');
                    } else {
                        this.isUnauthorized = true;
                    }
                } else {
                    this.currentTab = {
                        ...tab,
                        displayName: this.$t(tab.title)
                    };
                    if (response.data) {
                        this.isUnauthorized = false;
                    } else {
                        this.isUnauthorized = true;
                    }
                    if (updateRoute) {
                        this.$router.push({
                            name: 'BillingValidationData',
                            params: { tab: tab.route }
                        }).catch(err => {
                            if (err.name !== 'NavigationDuplicated') {
                                console.error(err);
                            }
                        });
                    }
                }
                this.isLoading = false;
            }).catch(() => {
                this.isLoading = false;
                // Optionally handle error
            });
        },
        changeTab(tab) {
            this.checkPrivilegeAndSetTab(tab, true);
        }
    }
}
</script>
<style scoped>
.disabled-tab {
    cursor: not-allowed;
}
</style>

